#include "interface.h"

#include <cstdint>
#include <vector>

namespace {

struct Candidate {
  int32_t score;
  int id;
};

static inline bool better(const Candidate& a, const Candidate& b) {
  return (a.score > b.score) || (a.score == b.score && a.id < b.id);
}

static inline uint64_t mix(uint64_t hash, uint64_t value) {
  hash ^= value;
  hash *= 1099511628211ULL;
  return hash;
}

}  // namespace

uint64_t beam_topk_checksum(const std::vector<int32_t>& logits, int beams, int vocab, int topk, int iters) {
  if (beams <= 0 || vocab <= 0 || topk <= 0 || iters <= 0) {
    return 0;
  }

  if (topk > vocab) topk = vocab;

  std::vector<Candidate> top(static_cast<std::size_t>(topk));
  uint64_t hash = 0;

  for (int iter = 0; iter < iters; ++iter) {
    hash = 1469598103934665603ULL;

    for (int b = 0; b < beams; ++b) {
      const std::size_t base = static_cast<std::size_t>(b) * static_cast<std::size_t>(vocab);

      int filled = 0;
      for (int v = 0; v < vocab; ++v) {
        Candidate cur{logits[base + static_cast<std::size_t>(v)], v};

        if (filled < topk) {
          int pos = filled;
          while (pos > 0 && better(cur, top[static_cast<std::size_t>(pos - 1)])) {
            top[static_cast<std::size_t>(pos)] = top[static_cast<std::size_t>(pos - 1)];
            --pos;
          }
          top[static_cast<std::size_t>(pos)] = cur;
          ++filled;
        } else {
          if (!better(cur, top[static_cast<std::size_t>(topk - 1)])) {
            continue;
          }
          int pos = topk - 1;
          while (pos > 0 && better(cur, top[static_cast<std::size_t>(pos - 1)])) {
            top[static_cast<std::size_t>(pos)] = top[static_cast<std::size_t>(pos - 1)];
            --pos;
          }
          top[static_cast<std::size_t>(pos)] = cur;
        }
      }

      for (int k = 0; k < topk; ++k) {
        hash = mix(hash, static_cast<uint64_t>(static_cast<uint32_t>(top[static_cast<std::size_t>(k)].score)));
        hash = mix(hash, static_cast<uint64_t>(top[static_cast<std::size_t>(k)].id));
      }
    }
  }

  return hash;
}
